## HTML to PDF with Puppeteer

### Get into container as root
```
docker exec -it --user root n8n /bin/sh
````

### Create folder for JS script file

```
mkdir -p /usr/local/bin/scripts
```

### html-to-pdf.js
```javascript
const puppeteer = require('puppeteer-core');
const fs = require('fs');
const path = require('path');

(async () => {
  try {
    const args = process.argv.slice(2);
    if (args.length < 2) {
      console.error('Usage: node script.js <input.html> <output.pdf>');
      process.exit(1);
    }

    const inputHtmlPath = path.resolve(args[0]);
    const outputPdfPath = path.resolve(args[1]);

    if (!fs.existsSync(inputHtmlPath)) {
      console.error(`Input file does not exist: ${inputHtmlPath}`);
      process.exit(1);
    }

    console.log('Reading HTML from:', inputHtmlPath);
    const html = fs.readFileSync(inputHtmlPath, 'utf8');

    const browser = await puppeteer.launch({
      executablePath: '/usr/bin/chromium-browser', // verify path
      args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-dev-shm-usage']
    });

    const page = await browser.newPage();
    await page.setContent(html, { waitUntil: 'networkidle0' });

    console.log('Generating PDF to:', outputPdfPath);
    await page.pdf({
      path: outputPdfPath,
      format: 'A4',
      printBackground: true
    });

    await browser.close();

    if (fs.existsSync(outputPdfPath)) {
      console.log(`PDF generated successfully: ${outputPdfPath}`);
    } else {
      console.error('PDF was not created. Check Chromium path and permissions.');
    }

  } catch (error) {
    console.error('Error:', error.message);
    process.exit(1);
  }
})();

```

### Make it executable
```
chmod +x /usr/local/bin/scripts/html-to-pdf.js
```


### Install Puppeteer in the same folder
```
cd /usr/local/bin/scripts
npm init -y
npm install puppeteer-core
```
OR better ???
```
/usr/local/bin/scripts # apk update
/usr/local/bin/scripts # apk add --no-cache chromium nss freetype freetype-dev harfbuzz ca-certificates ttf-freefont
```
AND check that `Chromium` is installed
```
/usr/local/bin/scripts # which chromium
/usr/local/bin/scripts # which chromium-browser
```

